16			const projectID = params['projectId'];
17			await Promise.all(
18				data.commits.edges.map(async (edge) => {
19					const sha = edge.node.sha;
20					if (executionBySha[sha] !== undefined) return;
21					try {
22						const result = await client.request<{ executionByResultRev: { id: string } | null }>(
23							COMMIT_EXECUTION_QUERY,
24							{ projectID, sha }
