36			return `/nodes/${params['nodeId']}/projects/${params['projectId']}/executions/${executionId}`;
37		}
38	
39		function fmtDate(iso: string): string {
40			return new Date(iso).toLocaleString();
41		}
42	
43		function goNext() {
